```

**Step 2: 先写失败测试** `tests/test_auth.py`：
```python
from fastapi.testclient import TestClient
from app.main import app
from app.db.session import SessionLocal
from app.models.user import User


def setup_function():
    with SessionLocal() as db:
        db.query(User).delete()
        db.commit()


def test_register_user():
    client = TestClient(app)
    resp = client.post('/api/v1/auth/register', json={
        'email': 'lawyer@test.com',
        'name': '张律师',
        'password': 'secret123',
        'role': 'lawyer'
    })
    assert resp.status_code == 201
    assert resp.json()['email'] == 'lawyer@test.com'


def test_login_returns_token():
    client = TestClient(app)
    client.post('/api/v1/auth/register', json={
        'email': 'lawyer2@test.com', 'name': '李律师',
        'password': 'secret123', 'role': 'lawyer'
    })
    resp = client.post('/api/v1/auth/login', json={
        'email': 'lawyer2@test.com', 'password': 'secret123'
    })
    assert resp.status_code == 200
    assert 'access_token' in resp.json()


def test_login_wrong_password():
    client = TestClient(app)
    client.post('/api/v1/auth/register', json={
        'email': 'lawyer3@test.com', 'name': '王律师',
        'password': 'secret123', 'role': 'lawyer'
    })
    resp = client.post('/api/v1/auth/login', json={
        'email': 'lawyer3@test.com', 'password': 'wrongpass'
    })
    assert resp.status_code == 401


def test_get_me_with_token():
    client = TestClient(app)
    client.post('/api/v1/auth/register', json={
        'email': 'lawyer4@test.com', 'name': '赵律师',
        'password': 'secret123', 'role': 'lawyer'
    })
    login = client.post('/api/v1/auth/login', json={
        'email': 'lawyer4@test.com', 'password': 'secret123'
    })
    token = login.json()['access_token']
    resp = client.get('/api/v1/auth/me', headers={'Authorization': f'Bearer {token}'})
    assert resp.status_code == 200
    assert resp.json()['email'] == 'lawyer4@test.com'
```

