export async function login(email: string, password: string) {
  return apiFetch('/api/v1/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, password }),
  });
}

export async function register(email: string, name: string, password: string, role = 'lawyer') {
  return apiFetch('/api/v1/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, name, password, role }),
  });
}
```

创建 `apps/web/app/login/page.tsx`：
```tsx
'use client';
import { useState } from 'react';
import { login } from '@/lib/api';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [token, setToken] = useState('');
  const [error, setError] = useState('');

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault();
    setError('');
    try {
      const data = await login(email, password);
      setToken(data.access_token);
      if (typeof window !== 'undefined') {
        localStorage.setItem('token', data.access_token);
        window.location.href = '/dashboard';
      }
    } catch {
      setError('邮箱或密码错误');
    }
  }

  return (
    <main style={{ padding: '2rem', fontFamily: 'sans-serif', maxWidth: '400px', margin: '4rem auto' }}>
      <h1>LegalFlow Studio</h1>
      <h2>登录</h2>
      <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
        <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="邮箱" required />
        <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="密码" required />
        <button type="submit">登录</button>
      </form>
      {error && <p style={{ color: 'red' }}>{error}</p>}
    </main>
  );
}
```

